# Convert to JSON
ref_js = json.dumps(REF, ensure_ascii=False)
rem_js = json.dumps(REM, ensure_ascii=False)
acts_js = json.dumps(ACTS, ensure_ascii=False)

# Inject into HTML
# Find existing REF, REM, ACTS declarations and replace
import re

# Replace REF data
if 'const REF' in html:
    html = re.sub(r'const REF = \{.*?\};', f'const REF = {ref_js};', html, flags=re.DOTALL)
else:
    # Inject before Alpine init
    html = html.replace("document.addEventListener('alpine:init'", f"const REF = {ref_js};\nconst REM = {rem_js};\nconst ACTS = {acts_js};\n\ndocument.addEventListener('alpine:init'")

if 'const REM' in html:
    html = re.sub(r'const REM = \[.*?\];', f'const REM = {rem_js};', html, flags=re.DOTALL)

if 'const ACTS' in html:
    html = re.sub(r'const ACTS = \{.*?\};', f'const ACTS = {acts_js};', html, flags=re.DOTALL)

# Add to Alpine data: REF: REF, REM: REM, ACTS: ACTS,
if 'REMED:"' not in html:
    html = html.replace('REF: {}', 'REF: REF,\n  REM: REM,\n  ACTS: ACTS,')

with open('/home/home/Documents/New OpenCode Project/erph-pm/index.html', 'w') as f:
    f.write(html)

# Verify
m = re.search(r'<script>([\s\S]*?)</script>', html)
if m:
    with open('/tmp/check.js', 'w') as f:
        f.write(m.group(1))
    import subprocess
    r = subprocess.run(['node', '--check', '/tmp/check.js'], capture_output=True, text=True)
    if r.returncode == 0:
        print('JS: OK')
    else:
        print('JS ERROR:', r.stderr[:300])
    
print('Done. Size:', len(html))
